/**
 * Regression test for: Non-legacy mail content fails to decrypt
 *
 * Issue: Users who have accounts with the new (non-legacy) permission model report that opening
 * certain emails results in blank message bodies. The issue specifically affects mails that use
 * owner-encrypted session keys under the new permission model.
 *
 * Root cause: When the application loads supplementary mail data (body content, draft details),
 * the session key needed for decryption is available from the parent mail object but is not being
 * passed through to the entity loading and caching layers.
 */

import o from "@tutao/otest"
import {
	aes128Decrypt,
	aes128Encrypt,
	aes128RandomKey,
	bitArrayToUint8Array,
	ENABLE_MAC,
	encryptKey,
	encryptRsaKey,
	IV_BYTE_LENGTH,
	random,
} from "@tutao/tutanota-crypto"
import { RsaWeb } from "../app/src/api/worker/crypto/RsaImplementation.js"
import {
	base64ToUint8Array,
	downcast,
	hexToPrivateKey,
	hexToPublicKey,
	neverNull,
	stringToUtf8Uint8Array,
	uint8ArrayToBase64,
	utf8Uint8ArrayToString,
} from "@tutao/tutanota-utils"
import {
	createBody,
	createMail,
	createMailAddress,
	createMailDetails,
	createMailDetailsBlob,
	MailBodyTypeRef,
	MailDetailsBlobTypeRef,
	MailDetailsTypeRef,
	MailTypeRef,
} from "../app/src/api/entities/tutanota/TypeRefs.js"
import {
	createBucket,
	createBucketKey,
	createBucketPermission,
	createGroup,
	createGroupMembership,
	createInstanceSessionKey,
	createKeyPair,
	createPermission,
	createTypeInfo,
	createUser,
	BucketPermissionTypeRef,
	BucketKeyTypeRef,
	GroupTypeRef,
	PermissionTypeRef,
	UserIdReturnTypeRef,
} from "../app/src/api/entities/sys/TypeRefs.js"
import { CryptoFacade } from "../app/src/api/worker/crypto/CryptoFacade.js"
import { InstanceMapper, decryptValue } from "../app/src/api/worker/crypto/InstanceMapper.js"
import { EntityClient } from "../app/src/api/common/EntityClient.js"
import { RestClient } from "../app/src/api/worker/rest/RestClient.js"
import { DefaultEntityRestCache } from "../app/src/api/worker/rest/DefaultEntityRestCache.js"
import { EntityRestClient } from "../app/src/api/worker/rest/EntityRestClient.js"
import { resolveTypeReference, typeModels } from "../app/src/api/common/EntityFunctions.js"
import { SessionKeyNotFoundError } from "../app/src/api/common/error/SessionKeyNotFoundError.js"
import { BlobAccessTokenFacade } from "../app/src/api/worker/facades/BlobAccessTokenFacade.js"
import { UserFacade } from "../app/src/api/worker/facades/UserFacade.js"
import { OwnerEncSessionKeysUpdateQueue } from "../app/src/api/worker/crypto/OwnerEncSessionKeysUpdateQueue.js"
import { object, when, matchers } from "testdouble"
import { assertThrows } from "@tutao/tutanota-test-utils"

o.spec("Regression: Non-legacy mail content fails to decrypt", function () {
	const rsa = new RsaWeb()
	const rsaPrivateHexKey =
		""
	const rsaPublicHexKey =
		""

	let crypto: CryptoFacade
	let instanceMapper: InstanceMapper
	let userFacade: UserFacade
	let ownerEncSessionKeysUpdateQueue: OwnerEncSessionKeysUpdateQueue

	o.beforeEach(async function () {
		const suspensionHandler = downcast({})
		const restClient = new RestClient(suspensionHandler)
		const blobAccessTokenFacade = object<BlobAccessTokenFacade>()
		const cache = new DefaultEntityRestCache()
		const entityRestClient = new EntityRestClient(
			downcast({}),
			restClient,
			() => crypto,
			instanceMapper,
			blobAccessTokenFacade,
		)

		instanceMapper = new InstanceMapper()
		ownerEncSessionKeysUpdateQueue = new OwnerEncSessionKeysUpdateQueue()
		userFacade = object<UserFacade>()
		const entityClient = new EntityClient(entityRestClient)

		// Create a mock UserFacade that will be used by CryptoFacade
		const logins = downcast({
			getUserId: () => "userId",
			isAdminLogin: () => false,
			isInternalUserLoggedIn: () => true,
			getLoggedInUser: () => ({
				_id: "userId",
			}),
		})

		const serviceExecutor = downcast({
			execUserService: async (service: any) => {
				return null
			},
		})

		crypto = new CryptoFacade(
			logins,
			entityClient,
			userFacade,
			ownerEncSessionKeysUpdateQueue,
			serviceExecutor,
		)
	})

	o(
		"Non-legacy mail with owner-encrypted session key fails to decrypt MailDetailsBlob when session key is not propagated",
		async function () {
			// Setup test data
			const userId = "userId"
			const groupId = "groupId"
			const userGroupId = "userGroupId"
			const mailListId = "mailListId"
			const mailElementId = "mailElementId"
			const mailDetailsBlobArchiveId = "mailDetailsBlobArchiveId"
			const mailDetailsBlobElementId = "mailDetailsBlobElementId"

			// Create RSA keys for encryption
			const privateKey = hexToPrivateKey(rsaPrivateHexKey)
			const publicKey = hexToPublicKey(rsaPublicHexKey)

			// Create the session key for mail (this would normally be generated on the server)
			const mailSessionKey = aes128RandomKey()

			// Create the session key for MailDetailsBlob
			const mailDetailsBlobSessionKey = aes128RandomKey()

			// Encrypt the MailDetailsBlob session key with the mail's owner key
			const encryptedMailDetailsBlobSessionKey = encryptRsaKey(publicKey, mailDetailsBlobSessionKey)

			// Create a mock mail with owner-encrypted session key
			const mail = createMail({
				_id: [mailListId, mailElementId],
				_ownerGroup: groupId,
				_ownerEncSessionKey: bitArrayToUint8Array(
					encryptKey(privateKey, bitArrayToUint8Array(mailSessionKey)),
				),
				subject: "Test Non-Legacy Mail",
				sender: createMailAddress({
					_id: "senderId",
					address: "sender@example.com",
					name: "Sender",
				}),
				toRecipients: [],
				ccRecipients: [],
				bccRecipients: [],
				replyTos: [],
				attachments: [],
				headers: null,
				conversationEntry: [mailListId, "conversationId"],
				receivedDate: new Date(),
				sentDate: null,
				subject: "Test",
				mailDetails: [mailDetailsBlobArchiveId, mailDetailsBlobElementId], // Points to MailDetailsBlob
			})

			// Create a Body with encrypted text (requires a session key to decrypt)
			const bodyText = "This is the confidential mail body content"
			const bodySessionKey = aes128RandomKey()
			const encryptedBodyText = uint8ArrayToBase64(
				aes128Encrypt(bodySessionKey, stringToUtf8Uint8Array(bodyText), null, true),
			)

			const body = createBody({
				_id: "bodyId",
				_owner: userId,
				_ownerGroup: groupId,
				_ownerEncSessionKey: bitArrayToUint8Array(
					encryptKey(privateKey, bitArrayToUint8Array(bodySessionKey)),
				),
				text: encryptedBodyText,
				compressedText: null,
			})

			// Create a MailDetailsBlob with owner-encrypted session key
			const mailDetailsBlob = createMailDetailsBlob({
				_id: [mailDetailsBlobArchiveId, mailDetailsBlobElementId],
				_owner: userId,
				_ownerGroup: groupId,
				_ownerEncSessionKey: encryptedMailDetailsBlobSessionKey,
				details: createMailDetails({
					_id: "detailsId",
					body: body,
					headers: null,
					recipients: downcast({}),
					replyTos: [],
					authStatus: "0",
					sentDate: new Date(),
				}),
			})

			// Test decryption: In the current bug, when loadMultiple is called for MailDetailsBlob,
			// the session key from mail is not passed through, causing decryption to fail.
			//
			// The flow is:
			// 1. Load MailDetailsBlob via loadMultiple (batch load)
			// 2. _handleLoadMultipleResult calls _decryptMapAndMigrate for each entity
			// 3. _decryptMapAndMigrate calls resolveSessionKey without owner key parameter
			// 4. CryptoFacade tries to resolve the key from permissions/cache
			// 5. If the key is not in cache and permission resolution fails, decryption fails
			//
			// The bug is that there's no way to pass the owner key from the parent Mail object
			// to the entity loading layer.

			// Try to decrypt the MailDetailsBlob without providing the owner key
			// This simulates the scenario where the session key from Mail is not available
			const mailDetailsBlobModel = await resolveTypeReference(MailDetailsBlobTypeRef)

			// Create a raw encrypted MailDetailsBlob (as it would come from the server)
			const encryptedMailDetailsBlobData = {
				_id: [mailDetailsBlobArchiveId, mailDetailsBlobElementId],
				_owner: userId,
				_ownerGroup: groupId,
				_ownerEncSessionKey: uint8ArrayToBase64(encryptedMailDetailsBlobSessionKey),
				details: {
					_id: "detailsId",
					body: {
						_id: "bodyId",
						_owner: userId,
						_ownerGroup: groupId,
						_ownerEncSessionKey: uint8ArrayToBase64(
							bitArrayToUint8Array(
								encryptKey(privateKey, bitArrayToUint8Array(bodySessionKey)),
							),
						),
						text: encryptedBodyText,
						compressedText: null,
					},
					headers: null,
					recipients: {},
					replyTos: [],
					authStatus: "0",
					sentDate: new Date().toISOString(),
				},
			}

			// Without the owner key passed through, resolveSessionKey will fail
			// because the key is not in the cache and cannot be resolved from permissions
			let sessionKeyResolutionFailed = false
			try {
				// This should throw SessionKeyNotFoundError because:
				// 1. The session key is owner-encrypted
				// 2. No owner key is provided to decrypt it
				// 3. The key is not in the cache
				// 4. Permission-based resolution will fail without the proper owner group setup
				await crypto.resolveSessionKey(mailDetailsBlobModel, encryptedMailDetailsBlobData)
			} catch (e) {
				if (e instanceof SessionKeyNotFoundError) {
					sessionKeyResolutionFailed = true
				} else {
					throw e
				}
			}

			// This assertion demonstrates the bug: session key resolution fails for non-legacy mails
			// with owner-encrypted session keys when the key is not propagated
			o(sessionKeyResolutionFailed).equals(
				true,
				"Expected SessionKeyNotFoundError when loading non-legacy mail without session key propagation",
			)
		},
	)

	o(
		"Batch loading multiple non-legacy mails fails without per-entity session key propagation",
		async function () {
			// This test demonstrates the batch loading issue mentioned in the bug report:
			// "Additionally, batch loading of multiple entities has the same propagation gap —
			// when loading several related items at once, the per-entity session keys are not
			// forwarded to the decryption step."

			const privateKey = hexToPrivateKey(rsaPrivateHexKey)
			const publicKey = hexToPublicKey(rsaPublicHexKey)

			// Create multiple MailDetailsBlobs, each with their own owner-encrypted session key
			const mailDetailsBlobSessionKey1 = aes128RandomKey()
			const mailDetailsBlobSessionKey2 = aes128RandomKey()

			const encryptedMailDetailsBlobSessionKey1 = encryptRsaKey(publicKey, mailDetailsBlobSessionKey1)
			const encryptedMailDetailsBlobSessionKey2 = encryptRsaKey(publicKey, mailDetailsBlobSessionKey2)

			// Create encrypted data for multiple MailDetailsBlobs
			const encryptedMailDetailsBlobData1 = {
				_id: ["archive1", "blob1"],
				_owner: "userId",
				_ownerGroup: "groupId",
				_ownerEncSessionKey: uint8ArrayToBase64(encryptedMailDetailsBlobSessionKey1),
				details: {
					_id: "details1",
					body: createBody({ _id: "body1" }),
					headers: null,
					recipients: {},
					replyTos: [],
					authStatus: "0",
					sentDate: new Date().toISOString(),
				},
			}

			const encryptedMailDetailsBlobData2 = {
				_id: ["archive2", "blob2"],
				_owner: "userId",
				_ownerGroup: "groupId",
				_ownerEncSessionKey: uint8ArrayToBase64(encryptedMailDetailsBlobSessionKey2),
				details: {
					_id: "details2",
					body: createBody({ _id: "body2" }),
					headers: null,
					recipients: {},
					replyTos: [],
					authStatus: "0",
					sentDate: new Date().toISOString(),
				},
			}

			// When batch loading, there's no mechanism to associate each entity with its owner key
			// This means _decryptMapAndMigrate will fail to resolve session keys for each entity
			const mailDetailsBlobModel = await resolveTypeReference(MailDetailsBlobTypeRef)

			let batchResolutionFailed = false
			try {
				// Simulate batch decryption without owner key propagation
				await crypto.resolveSessionKey(mailDetailsBlobModel, encryptedMailDetailsBlobData1)
			} catch (e) {
				if (e instanceof SessionKeyNotFoundError) {
					batchResolutionFailed = true
				} else {
					throw e
				}
			}

			o(batchResolutionFailed).equals(
				true,
				"Expected batch loading to fail when session keys are not propagated per entity",
			)
		},
	)
})

