\t\trecipients: {},\n\t\t\t\t\treplyTos: [],\n\t\t\t\t\tauthStatus: \"0\",\n\t\t\t\t\tsentDate: new Date().toISOString(),\n\t\t\t\t},\n\t\t\t}\n\n\t\t\tconst encryptedMailDetailsBlobData2 = {\n\t\t\t\t_id: [\"archive2\", \"blob2\"],\n\t\t\t\t_owner: \"userId\",\n\t\t\t\t_ownerGroup: \"groupId\",\n\t\t\t\t_ownerEncSessionKey: uint8ArrayToBase64(encryptedMailDetailsBlobSessionKey2),\n\t\t\t\tdetails: {\n\t\t\t\t\t_id: \"details2\",\n\t\t\t\t\tbody: createBody({ _id: \"body2\" }),\n\t\t\t\t\theaders: null,\n\t\t\t\t\trecipients: {},\n\t\t\t\t\treplyTos: [],\n\t\t\t\t\tauthStatus: \"0\",\n\t\t\t\t\tsentDate: new Date().toISOString(),\n\t\t\t\t},\n\t\t\t}\n\n\t\t\t// When batch loading, there's no mechanism to associate each entity with its owner key\n\t\t\t// This means _decryptMapAndMigrate will fail to resolve session keys for each entity\n\t\t\tconst mailDetailsBlobModel = await resolveTypeReference(MailDetailsBlobTypeRef)\n\n\t\t\tlet batchResolutionFailed = false\n\t\t\ttry {\n\t\t\t\t// Simulate batch decryption without owner key propagation\n\t\t\t\tawait crypto.resolveSessionKey(mailDetailsBlobModel, encryptedMailDetailsBlobData1)\n\t\t\t} catch (e) {\n\t\t\t\tif (e instanceof SessionKeyNotFoundError) {\n\t\t\t\t\tbatchResolutionFailed = true\n\t\t\t\t} else {\n\t\t\t\t\tthrow e\n\t\t\t\t}\n\t\t\t}\n\n\t\t\texpect(batchResolutionFailed).toBe(\n\t\t\t\ttrue,\n\t\t\t)\n\t\t},\n\t)\n})\n", "structuredPatch": [{"oldStart": 8, "oldLines": 330, "newStart": 8, "newLines": 224, "lines": ["  * Root cause: When the application loads supplementary mail data (body content, draft details),", "  * the session key needed for decryption is available from the parent mail object but is not being", "  * passed through to the entity loading and caching layers.", "+ *", "+ * This manifests in two ways:", "+ * 1. Single entity loading: Session key from parent Mail is not provided to load() method", "+ * 2. Batch loading: No mechanism to pass per-entity session keys in loadMultiple()"